query tournamentList {
      tournamentList {
        id
        code
        frontEndId
        nameProfileId
        isInteractiveServiceAvailable
        name_ch
        name_en
        sequence
      }
    }

{
  betConfirmationFeatureShortcut {
    btnLabel_ch
    btnLabel_en
    content_ch
    content_en
    title_ch
    title_en
  }
  jcbwControl {
    enableBetConfirmationFeatureShortcut4e
  }
}

query footballData($tday: Int!, $tIdList:[String]!) {
        timeOffset {
          fb
        }
        fullTourns: tournaments(fbOddsTypes:  [ALL]) {
          frontEndId
          nameProfileId
        }
        chpTypes: tournaments(fbOddsTypes:  [CHP]) {
          foPools(fbOddsTypes: [CHP]) {
            chpType
          }
        }
        tournaments(fbOddsTypes:  [TQL, GPF, GPW, TPS, TSP]) {
          nameProfileId
          name_en
          name_ch
          sequence
        }
        tournamentResult(oddsTypes: [TQL, GPF, GPW, TPS, TSP], tournDayFilter: { days: $tday, exceptionalTournIDs: $tIdList }) {
          id
          name_en
          name_ch
          sequence
        }
        featuredMatches : matches(fbOddsTypes: [ALL, HAD, EHA], featuredMatchesOnly: true) {
          id
        }
      }

query sp4e_FBPoolConfig {
  poolConfigs {
    betType
    allUpMaxLeg
    minBet
  }
}

query importantNotices($category: [RemarkCategory]!) {
